CREATE TABLE sustainable_urbanism (id INT, city VARCHAR(50), project_type VARCHAR(50)); INSERT INTO sustainable_urbanism (id, city, project_type) VALUES (1, 'Oakland', 'Affordable Housing'), (2, 'Seattle', 'Green Spaces');
Q: How many sustainable urbanism projects are in Oakland?
A: SELECT COUNT(*) FROM sustainable_urbanism WHERE city = 'Oakland';

CREATE TABLE mining_unions.strikes (id INT, union TEXT, year INT, duration INT);
Q: How many strikes took place in 'mining_unions' in the year 2010?
A: SELECT COUNT(*) FROM mining_unions.strikes WHERE year = 2010 AND union_member = TRUE;

CREATE TABLE MissionData (name VARCHAR(50), type VARCHAR(15), duration INT); INSERT INTO MissionData (name, type, duration) VALUES ('Ares 1', 'Low Earth Orbit', 150), ('Artemis 1', 'Deep Space', 300), ('Apollo 11', 'Low Earth Orbit', 200), ('Voyager 1', 'Deep Space', 400);
Q: What is the maximum duration of 'Deep Space' missions?
A: SELECT MAX(duration) FROM MissionData WHERE type = 'Deep Space';

CREATE TABLE Suppliers (supplierID INT, name VARCHAR(50), material VARCHAR(20), sustainabilityScore INT); INSERT INTO Suppliers (supplierID, name, material, sustainabilityScore) VALUES (1, 'GreenFibers', 'Organic Cotton', 90), (2, 'EcoFabrics', 'Recycled Polyester', 85), (3, 'SustainableTextiles', 'Hemp', 95), (4, 'FairTradeFibers', 'Organic Cotton', 88);
Q: Who are the suppliers of organic cotton with sustainability scores above 85?
A: SELECT name, sustainabilityScore FROM Suppliers WHERE material = 'Organic Cotton' AND sustainabilityScore > 85;

CREATE TABLE Farm (region VARCHAR(255), stock_count INT); INSERT INTO Farm (region, stock_count) VALUES ('South Atlantic', 600), ('South Atlantic', 1100), ('South Pacific', 1300);
Q: List the farms in the South Atlantic region with a stock count between 500 and 1500?
A: SELECT * FROM Farm WHERE region = 'South Atlantic' AND stock_count BETWEEN 500 AND 1500;

CREATE TABLE infrastructure (id INT, name TEXT, region TEXT, year INT);CREATE TABLE projects (id INT, name TEXT, region TEXT, year INT);
Q: What is the total number of rural infrastructure projects and community development projects in 'rural_development' database, grouped by region and year?
A: SELECT region, year, COUNT(DISTINCT infrastructure.id) + COUNT(DISTINCT projects.id) FROM infrastructure FULL OUTER JOIN projects ON infrastructure.region = projects.region AND infrastructure.year = projects.year GROUP BY region, year;

CREATE TABLE tv_shows (id INT, title VARCHAR(255), release_year INT, viewership INT); INSERT INTO tv_shows (id, title, release_year, viewership) VALUES (1, 'TVShowA', 2021, 6000000); INSERT INTO tv_shows (id, title, release_year, viewership) VALUES (2, 'TVShowB', 2019, 4000000); INSERT INTO tv_shows (id, title, release_year, viewership) VALUES (3, 'TVShowC', 2022, 7000000);
Q: Which TV shows have a release year higher than 2020 and viewership greater than 5 million?
A: SELECT title, release_year, viewership FROM tv_shows WHERE release_year > 2020 AND viewership > 5000000;

CREATE TABLE arabian_sea (id INT, well_name VARCHAR(255), drill_date DATE, daily_production_oil FLOAT);
Q: What is the minimum daily production rate of oil wells in the Arabian Sea that were drilled after 2018?
A: SELECT MIN(daily_production_oil) as min_daily_production_oil FROM arabian_sea WHERE drill_date > '2018-12-31';

CREATE TABLE tech_for_social_good (id INT PRIMARY KEY, project VARCHAR(100), description TEXT);
Q: Insert a new record into the 'tech_for_social_good' table with an id of 4, a project name of 'Assistive technology for people with disabilities', and a description of 'Technology to improve the quality of life for people with disabilities'
A: INSERT INTO tech_for_social_good (id, project, description) VALUES (4, 'Assistive technology for people with disabilities', 'Technology to improve the quality of life for people with disabilities');

CREATE TABLE au_peacekeeping (id INT, year INT, location VARCHAR(50)); INSERT INTO au_peacekeeping (id, year, location) VALUES (1, 2018, 'Somalia'), (2, 2019, 'Somalia'), (3, 2020, 'South Sudan'), (4, 2021, 'Mali');
Q: Which peacekeeping operations were carried out by the African Union in 2020?
A: SELECT location FROM au_peacekeeping WHERE year = 2020;

CREATE TABLE game_reviews (review_id INT, game TEXT, review_score INT); INSERT INTO game_reviews (review_id, game, review_score) VALUES (1, 'Assassin’s Creed', 85), (2, 'Fortnite', 80), (3, 'Splinter Cell', 90); CREATE TABLE games (game_id INT, game TEXT, genre TEXT, studio TEXT); INSERT INTO games (game_id, game, genre, studio) VALUES (1, 'Assassin’s Creed', 'Action-Adventure', 'Ubisoft'), (2, 'Fortnite', 'Battle Royale', 'Epic Games'), (3, 'Splinter Cell', 'Stealth', 'Ubisoft');
Q: What are the average review scores for action-adventure games, grouped by studio?
A: SELECT games.studio, AVG(game_reviews.review_score) FROM game_reviews JOIN games ON game_reviews.game = games.game WHERE games.genre = 'Action-Adventure' GROUP BY games.studio;

CREATE TABLE law_violations (id INTEGER, vessel_size INTEGER, location TEXT, year INTEGER); INSERT INTO law_violations (id, vessel_size, location, year) VALUES (1, 250, 'Southeast Asia', 2020), (2, 150, 'Southeast Asia', 2020), (3, 300, 'Indian Ocean', 2020);
Q: What is the average size of vessels that violated maritime law in Southeast Asia in 2020?
A: SELECT AVG(vessel_size) FROM law_violations WHERE location = 'Southeast Asia' AND year = 2020;

CREATE TABLE spacecraft (id INT, name VARCHAR(255), total_days_in_space INT); INSERT INTO spacecraft (id, name, total_days_in_space) VALUES (1, 'Voyager 1', 43902), (2, 'Voyager 2', 41484), (3, 'Cassini', 13303);
Q: Which spacecraft has the longest duration in space?
A: SELECT name, total_days_in_space FROM spacecraft ORDER BY total_days_in_space DESC LIMIT 1;

CREATE TABLE MedicalCheckups (id INT, astronaut_name VARCHAR(255), checkup_date DATE, duration INT); INSERT INTO MedicalCheckups (id, astronaut_name, checkup_date, duration) VALUES (1, 'Mark Watney', '2021-01-01', 30), (2, 'Melissa Lewis', '2021-02-15', 45);
Q: What is the maximum medical checkup duration for astronauts who had medical checkups in '2021'?
A: SELECT MAX(duration) FROM MedicalCheckups WHERE checkup_date >= '2021-01-01' AND checkup_date < '2022-01-01';

CREATE TABLE clients (client_id INT, name VARCHAR(50), region VARCHAR(20), account_balance DECIMAL(10, 2)); INSERT INTO clients (client_id, name, region, account_balance) VALUES (1, 'John Doe', 'Western', 25000.00), (2, 'Jane Smith', 'Eastern', 30000.00), (3, 'Mike Johnson', 'Western', 40000.00);
Q: Find the top 3 clients with the highest account balances in the Western region.
A: SELECT client_id, name, account_balance FROM clients WHERE region = 'Western' ORDER BY account_balance DESC LIMIT 3;

CREATE TABLE chemicals (chemical_id INT, chemical_name VARCHAR(50)); CREATE TABLE safety_incidents (incident_id INT, chemical_id INT, incident_date DATE); INSERT INTO chemicals (chemical_id, chemical_name) VALUES (1, 'Chemical A'), (2, 'Chemical B'); INSERT INTO safety_incidents (incident_id, chemical_id, incident_date) VALUES (1, 1, '2022-01-01'), (2, 2, '2022-01-01');
Q: How many safety incidents were recorded for each chemical in the past 6 months?
A: SELECT chemicals.chemical_name, COUNT(safety_incidents.incident_id) FROM chemicals LEFT JOIN safety_incidents ON chemicals.chemical_id = safety_incidents.chemical_id WHERE safety_incidents.incident_date >= DATE_SUB(CURDATE(), INTERVAL 6 MONTH) GROUP BY chemicals.chemical_name;

CREATE TABLE virtual_tours (location TEXT, month TEXT, engagement INT); INSERT INTO virtual_tours (location, month, engagement) VALUES ('New York', 'November', 500), ('Los Angeles', 'November', 700), ('Toronto', 'November', 600), ('Miami', 'November', 800), ('Chicago', 'November', 400); CREATE TABLE locations (location TEXT, region TEXT); INSERT INTO locations (location, region) VALUES ('New York', 'North America'), ('Los Angeles', 'North America'), ('Toronto', 'North America'), ('Miami', 'North America'), ('Chicago', 'North America');
Q: How many virtual tours were engaged in 'North America' in the month of 'November'?
A: SELECT SUM(engagement) FROM virtual_tours vt JOIN locations l ON vt.location = l.location WHERE l.region = 'North America' AND vt.month = 'November';

CREATE TABLE policy_advocacy_transportation (id INT, title TEXT, transportation_type TEXT); INSERT INTO policy_advocacy_transportation (id, title, transportation_type) VALUES (1, 'Policy 1', 'Public Transportation'), (2, 'Policy 2', 'Para-transit'), (3, 'Policy 3', 'Rideshare'), (4, 'Policy 4', 'Bicycle');
Q: List the names of all policy advocacy initiatives related to accessible transportation.
A: SELECT title FROM policy_advocacy_transportation WHERE transportation_type IS NOT NULL;

CREATE TABLE Wearable (DeviceID INT PRIMARY KEY, MemberID INT, Steps INT, Date DATE); CREATE TABLE Member (MemberID INT PRIMARY KEY, Age INT, Gender VARCHAR(10), MembershipStart DATE);
Q: What is the maximum number of steps taken by members, grouped by age?
A: SELECT Member.Age, MAX(Wearable.Steps) FROM Wearable INNER JOIN Member ON Wearable.MemberID = Member.MemberID GROUP BY Member.Age;

CREATE TABLE exhibitions (visitor_id INT, visit_date DATE, exhibition_category VARCHAR(10)); INSERT INTO exhibitions (visitor_id, visit_date, exhibition_category) VALUES (1, '2021-06-01', 'Art'), (2, '2021-06-02', 'Science');
Q: What was the average age of visitors who attended exhibitions in 'Art' category?
A: SELECT AVG(DATEDIFF(y, birth_date, visit_date)) AS avg_age FROM visitors JOIN exhibitions ON visitors.id = exhibitions.visitor_id WHERE exhibitions.exhibition_category = 'Art';

CREATE TABLE Restaurants (RestaurantID int, RestaurantName varchar(255)); CREATE TABLE Inspections (InspectionID int, RestaurantID int, InspectionGrade varchar(10), InspectionDate date);
Q: List all food safety inspections with a passing grade, their corresponding restaurant, and the date of inspection.
A: SELECT R.RestaurantName, I.InspectionGrade, I.InspectionDate FROM Restaurants R INNER JOIN Inspections I ON R.RestaurantID = I.RestaurantID WHERE I.InspectionGrade = 'Pass';

CREATE TABLE athletes (id INT PRIMARY KEY, name VARCHAR(50), age INT, team VARCHAR(50));
Q: Insert athlete records into the "athletes" table for new athletes
A: INSERT INTO athletes (id, name, age, team) VALUES (1, 'Michael Jordan', 50, 'Bulls'), (2, 'Serena Williams', 40, 'Eagles');

CREATE TABLE SpendingData (Year INT, Country VARCHAR(255), Tourists INT, Spending DECIMAL(10,2)); INSERT INTO SpendingData (Year, Country, Tourists, Spending) VALUES (2019, 'Indonesia', 12000000, 650), (2019, 'Malaysia', 9000000, 800), (2019, 'Singapore', 7000000, 1200), (2019, 'Thailand', 15000000, 900), (2019, 'Philippines', 8000000, 450);
Q: What is the percentage of international tourists in Southeast Asia who spent more than $1000 in 2019?
A: SELECT (SUM(CASE WHEN Spending > 1000 THEN 1 ELSE 0 END) * 100.0 / COUNT(*)) AS Percentage FROM SpendingData WHERE Country IN ('Indonesia', 'Malaysia', 'Singapore', 'Thailand', 'Philippines') AND Year = 2019;

CREATE TABLE Community_Health_Workers (Worker_ID INT, Name VARCHAR(255), Training_Topic VARCHAR(255), Completion_Date DATE); INSERT INTO Community_Health_Workers (Worker_ID, Name, Training_Topic, Completion_Date) VALUES (1, 'Jamila', 'Cultural Competency 101', '2022-06-01'), (2, 'Luis', 'Cultural Competency 101', '2022-05-15');
Q: List the cultural competency training topics for Community Health Workers and their respective completion dates.
A: SELECT Training_Topic, Completion_Date FROM Community_Health_Workers WHERE Training_Topic LIKE '%Cultural Competency%';

CREATE TABLE Sales_Channels (channel_id INT, channel_name VARCHAR(50)); INSERT INTO Sales_Channels (channel_id, channel_name) VALUES (1, 'Online'), (2, 'Retail'), (3, 'Wholesale'); CREATE TABLE Sales_Channel_Revenue (sale_id INT, channel_id INT, sale_date DATE, revenue DECIMAL(10,2)); INSERT INTO Sales_Channel_Revenue (sale_id, channel_id, sale_date, revenue) VALUES (1, 1, '2022-04-01', 5000), (2, 2, '2022-04-02', 6000), (3, 1, '2022-05-01', 7000), (4, 2, '2022-05-02', 8000);
Q: What was the total revenue for the 'Online' sales channel in Q2 2022?
A: SELECT S.channel_name, SUM(R.revenue) as total_revenue FROM Sales_Channel_Revenue R JOIN Sales_Channels S ON R.channel_id = S.channel_id WHERE S.channel_name = 'Online' AND R.sale_date BETWEEN '2022-04-01' AND '2022-06-30' GROUP BY S.channel_name;

CREATE TABLE Creative_AI_Apps_History (app_id INT, app_name VARCHAR(50), region VARCHAR(50), app_development_date DATE); INSERT INTO Creative_AI_Apps_History (app_id, app_name, region, app_development_date) VALUES (1, 'TextGen', 'Asia', '2018-01-01'), (2, 'ImageGen', 'China', '2019-05-12'), (3, 'MusicGen', 'Asia', '2020-11-15');
Q: How many creative AI applications were developed in the Asia region between 2018 and 2020, excluding applications developed in China?
A: SELECT COUNT(*) FROM Creative_AI_Apps_History WHERE region = 'Asia' AND app_development_date BETWEEN '2018-01-01' AND '2020-12-31' AND region != 'China';

CREATE TABLE Employees (EmployeeID INT, Department VARCHAR(20), Salary FLOAT); INSERT INTO Employees (EmployeeID, Department, Salary) VALUES (1, 'IT', 75000.00), (2, 'IT', 70000.00), (3, 'Engineering', 95000.00), (4, 'Finance', 85000.00);
Q: What is the maximum salary in the Engineering department?
A: SELECT MAX(Salary) FROM Employees WHERE Department = 'Engineering';

CREATE TABLE VRDevices (DeviceID INT, DeviceName VARCHAR(20));
Q: Insert new VR device 'Valve Index' into 'VRDevices' table.
A: INSERT INTO VRDevices (DeviceID, DeviceName) VALUES (4, 'Valve Index');

CREATE TABLE Food_Allergens (Product_ID INT, Allergen_ID INT); CREATE TABLE Allergens (Allergen_ID INT, Allergen_Name TEXT); CREATE TABLE Products (Product_ID INT, Product_Name TEXT, Organic_Certified INT); CREATE VIEW Products_With_Milk_Allergen AS SELECT Food_Allergens.Product_ID FROM Food_Allergens INNER JOIN Allergens ON Food_Allergens.Allergen_ID = Allergens.Allergen_ID WHERE Allergens.Allergen_Name = 'Milk'; CREATE VIEW Non_Organic_Products_With_Milk_Allergen AS SELECT * FROM Products_With_Milk_Allergen WHERE Products.Organic_Certified = 0;
Q: Which non-organic products contain milk as an allergen?
A: SELECT Product_Name FROM Non_Organic_Products_With_Milk_Allergen;

CREATE TABLE songs (id INT, title TEXT, year INT, genre TEXT); INSERT INTO songs (id, title, year, genre) VALUES (1, 'Song 4', 2015, 'Folk'), (2, 'Song 5', 2013, 'Folk'), (3, 'Song 6', 1999, 'Rock');
Q: What is the average release year of songs in the 'Folk' genre?
A: SELECT AVG(songs.year) FROM songs WHERE songs.genre = 'Folk';

CREATE TABLE refugee_support (id INT, refugee_id INT, country TEXT, year INT); CREATE TABLE refugees (id INT, name TEXT, country TEXT); INSERT INTO refugee_support (id, refugee_id, country, year) VALUES (1, 1, 'Jordan', 2020), (2, 1, 'Lebanon', 2020); INSERT INTO refugees (id, name) VALUES (1, 'Refugee1');
Q: How many refugees in Jordan and Lebanon received support from international organizations in 2020?
A: SELECT COUNT(*) FROM refugee_support rs JOIN refugees r ON rs.refugee_id = r.id WHERE rs.country IN ('Jordan', 'Lebanon') AND rs.year = 2020;

CREATE TABLE artists (id INT, name TEXT, genre TEXT); CREATE TABLE albums (id INT, title TEXT, artist_id INT, platform TEXT); CREATE TABLE sales (id INT, album_id INT, quantity INT, revenue DECIMAL); CREATE VIEW pop_mobile_albums AS SELECT a.id, a.title, ar.name FROM albums a JOIN artists ar ON a.artist_id = ar.id WHERE ar.genre = 'pop' AND a.platform = 'mobile'; CREATE VIEW pop_mobile_sales AS SELECT s.album_id, AVG(s.revenue) as avg_revenue FROM sales s JOIN pop_mobile_albums pma ON s.album_id = pma.id GROUP BY album_id;
Q: Calculate the average revenue per album for all pop albums available on the 'mobile' platform.
A: SELECT avg_revenue FROM pop_mobile_sales;

CREATE TABLE Community_Education (program VARCHAR(20), budget INT); INSERT INTO Community_Education (program, budget) VALUES ('Young_Conservationists', 9000), ('Eco_Rangers', 11000), ('Green_Neighbors', 8000);
Q: What is the average budget for community education programs?
A: SELECT AVG(budget) FROM Community_Education;

CREATE TABLE Produce (id INT PRIMARY KEY, name VARCHAR(255), type VARCHAR(255), price DECIMAL(5,2)); INSERT INTO Produce (id, name, type, price) VALUES (1, 'Apples', 'Organic', 1.99), (2, 'Bananas', 'Organic', 1.49);
Q: Find the average price of organic fruits in the 'Produce' table
A: SELECT AVG(price) FROM Produce WHERE type = 'Organic' AND name LIKE 'Fruits%';

CREATE TABLE marine_species_2 (name VARCHAR(255), region VARCHAR(255));   CREATE TABLE southern_ocean_2 (name VARCHAR(255), region_type VARCHAR(255));  INSERT INTO marine_species_2 (name, region) VALUES ('SPECIES3', 'Southern Ocean'), ('SPECIES4', 'Arctic Ocean');   INSERT INTO southern_ocean_2 (name, region_type) VALUES ('SPECIES3', 'Marine Species'), ('PENGUIN1', 'Marine Species');
Q: Which marine species are found in the Southern Ocean, excluding penguins?
A: SELECT marine_species_2.name FROM marine_species_2 LEFT JOIN southern_ocean_2 ON marine_species_2.name = southern_ocean_2.name WHERE southern_ocean_2.name IS NULL;

CREATE TABLE garments (id INT, name VARCHAR(100), category VARCHAR(50), price DECIMAL(5,2), sales_volume INT); CREATE TABLE sales (id INT, garment_id INT, date DATE, quantity INT); CREATE VIEW sales_summary AS SELECT garment_id, SUM(quantity) AS total_sold FROM sales GROUP BY garment_id; CREATE VIEW garments_sales AS SELECT garments.id, garments.name, garments.category, garments.price, sales_summary.total_sold FROM garments INNER JOIN sales_summary ON garments.id = sales_summary.garment_id; CREATE TABLE customers (id INT, name VARCHAR(100), gender VARCHAR(10), age INT);
Q: What are the top 5 most sold garments by sales volume?
A: SELECT garments.name, garments_sales.total_sold FROM garments_sales ORDER BY garments_sales.total_sold DESC LIMIT 5;

CREATE TABLE strains (strain_id INT, strain_name TEXT, strain_type TEXT, state TEXT, potency DECIMAL); INSERT INTO strains (strain_id, strain_name, strain_type, state, potency) VALUES (1, 'Purple Haze', 'Sativa', 'Washington', 18);
Q: What is the average potency of sativa strains sold in Washington state?
A: SELECT AVG(potency) FROM strains WHERE strain_type = 'Sativa' AND state = 'Washington';

CREATE TABLE Donors (DonorID int, DonorName varchar(50), Country varchar(50)); INSERT INTO Donors (DonorID, DonorName, Country) VALUES (1, 'John Doe', 'United States'); INSERT INTO Donors (DonorID, DonorName, Country) VALUES (2, 'Jane Smith', 'India'); INSERT INTO Donors (DonorID, DonorName, Country) VALUES (3, 'Alice Johnson', 'Japan');
Q: Show me the total number of donors from Asia.
A: SELECT COUNT(*) FROM Donors WHERE Donors.Country IN ('India', 'Japan');

CREATE TABLE media_representation (id INT, user_id INT, country VARCHAR(50), region VARCHAR(50), score INT); INSERT INTO media_representation (id, user_id, country, region, score) VALUES (1, 1, 'China', 'Asia', 80), (2, 2, 'Japan', 'Asia', 85), (3, 3, 'India', 'Asia', 75), (4, 4, 'Indonesia', 'Asia', 70), (5, 5, 'Pakistan', 'Asia', 65), (6, 6, 'Bangladesh', 'Asia', 60);
Q: Which countries have the highest and lowest media representation scores in Asia?
A: SELECT country, score FROM media_representation WHERE region = 'Asia' ORDER BY score DESC LIMIT 1; SELECT country, score FROM media_representation WHERE region = 'Asia' ORDER BY score ASC LIMIT 1;

CREATE TABLE models (id INT, name VARCHAR(255), region VARCHAR(255), is_fairness_test BOOLEAN); INSERT INTO models (id, name, region, is_fairness_test) VALUES (1, 'ModelA', 'US', true), (2, 'ModelB', 'EU', false), (3, 'ModelC', 'APAC', true);
Q: What is the total number of models trained and tested for fairness across all regions?
A: SELECT COUNT(*) FROM models WHERE is_fairness_test = true;

CREATE TABLE safety_incidents (id INT, incident_date DATE, region VARCHAR(255), incident_description VARCHAR(255)); INSERT INTO safety_incidents (id, incident_date, region, incident_description) VALUES (1, '2020-01-01', 'Asia', 'Chemical spill'), (2, '2019-12-31', 'Asia', 'Equipment malfunction');
Q: How many safety incidents were reported in the Asian region in the year 2020?
A: SELECT COUNT(*) FROM safety_incidents WHERE region = 'Asia' AND YEAR(incident_date) = 2020;

CREATE TABLE highways (id INT, name TEXT, length_km FLOAT, location TEXT, built YEAR); INSERT INTO highways (id, name, length_km, location, built) VALUES (1, 'Autobahn A9', 530.5, 'Germany', 1936); INSERT INTO highways (id, name, length_km, location, built) VALUES (2, 'I-90', 498.7, 'USA', 1956);
Q: What is the length and name of the longest highway segment built before 1980?
A: SELECT name, length_km FROM highways WHERE built < 1980 ORDER BY length_km DESC LIMIT 1;

CREATE TABLE element_2017 (element VARCHAR(10), quantity INT, price DECIMAL(5,2)); INSERT INTO element_2017 (element, quantity, price) VALUES ('Dy', 1200, 250.50), ('Tm', 800, 180.25), ('Y', 1500, 150.00);
Q: Which elements were produced in 2017 and their corresponding prices?
A: SELECT e.element, e.quantity, p.price FROM element_2017 e LEFT JOIN prices p ON e.element = p.element;

CREATE TABLE OpenDataInitiatives (id INT, initiative_name VARCHAR(50), country VARCHAR(50), launch_date DATE);
Q: How many open data initiatives were launched in South Korea since 2016?
A: SELECT COUNT(*) FROM OpenDataInitiatives WHERE country = 'South Korea' AND launch_date >= '2016-01-01';

CREATE TABLE Permits (PermitID int, PermitNumber varchar(255), IssueDate date, City varchar(255));
Q: What is the total number of building permits issued in New York City in the past year?
A: SELECT COUNT(PermitNumber) as TotalPermits FROM Permits WHERE IssueDate >= DATEADD(year, -1, GETDATE()) AND City = 'New York City';

CREATE TABLE waste_generation (id INT, sector VARCHAR(20), location VARCHAR(20), amount DECIMAL(10,2), date DATE); INSERT INTO waste_generation (id, sector, location, amount, date) VALUES (1, 'residential', 'New York City', 500, '2021-01-01');
Q: Delete records of waste generation from the residential sector in New York City in 2021.
A: DELETE FROM waste_generation WHERE sector = 'residential' AND location = 'New York City' AND date = '2021-01-01';

CREATE TABLE revenue (id INT, product_type VARCHAR(20), country VARCHAR(20), amount FLOAT); INSERT INTO revenue (id, product_type, country, amount) VALUES (1, 'organic', 'France', 1000), (2, 'non-organic', 'France', 1500);
Q: What is the total revenue from organic food sales in the EU?
A: SELECT SUM(amount) FROM revenue WHERE product_type = 'organic' AND country IN ('EU countries');

CREATE TABLE regions (id INT, region VARCHAR(50)); CREATE TABLE workers (id INT, name VARCHAR(50), region VARCHAR(50), salary DECIMAL(10,2)); INSERT INTO regions (id, region) VALUES (1, 'North'), (2, 'South'), (3, 'East'), (4, 'West'); INSERT INTO workers (id, name, region, salary) VALUES (1, 'Sara', 'North', 50000.00), (2, 'Jack', 'South', 45000.00), (3, 'Olivia', 'East', 60000.00), (4, 'Liam', 'West', 55000.00), (5, 'Ava', 'North', 52000.00), (6, 'Noah', 'South', 48000.00), (7, 'Mia', 'East', 62000.00), (8, 'Ethan', 'West', 58000.00);
Q: Display the total salary paid to workers in the renewable energy sector, broken down by region.
A: SELECT w.region, SUM(w.salary) as total_salary FROM workers w INNER JOIN regions r ON w.region = r.region WHERE w.industry = 'Renewable Energy' GROUP BY w.region;

CREATE VIEW large_donors AS SELECT * FROM donors WHERE donation_amount > 1000;
Q: How many unique donors are there in the 'large_donors' view?
A: SELECT COUNT(DISTINCT donor_id) FROM large_donors;

CREATE TABLE Sales (SaleID int, Genre varchar(50), SalesDate date, Revenue decimal(10,2)); INSERT INTO Sales VALUES (1, 'Latin Pop', '2021-01-01', 5000); INSERT INTO Sales VALUES (2, 'Reggaeton', '2021-02-01', 7000); INSERT INTO Sales VALUES (3, 'Salsa', '2021-03-01', 6000);
Q: What is the total revenue generated by Latin music genres in 2021?
A: SELECT SUM(Revenue) as TotalRevenue FROM Sales WHERE Genre like 'Latin%' AND YEAR(SalesDate) = 2021;

CREATE TABLE sales_data (id INT, equipment_name TEXT, sale_date DATE, quantity INT, total_cost FLOAT);
Q: remove all records with total cost greater than 50000000 from sales_data
A: DELETE FROM sales_data WHERE total_cost > 50000000;

CREATE TABLE ImpactInvestments (InvestmentID INT, ROI DECIMAL(5,2), Region VARCHAR(50));
Q: List the impact investments with a return on investment greater than 10% in Southeast Asia.
A: SELECT InvestmentID, ROI FROM ImpactInvestments WHERE ROI > 10 AND Region = 'Southeast Asia';

CREATE TABLE cases (case_id INT, judge_race VARCHAR(20), state VARCHAR(20), open_date DATE); INSERT INTO cases (case_id, judge_race, state, open_date) VALUES (1, 'White', 'California', '2019-01-01'), (2, 'Black', 'California', '2020-01-01'), (3, 'Asian', 'California', '2019-01-01');
Q: How many criminal cases were open in the state of California on January 1, 2020 that were resolved by a judge who is a member of a racial or ethnic minority?
A: SELECT COUNT(*) FROM cases WHERE state = 'California' AND open_date < '2020-01-01' AND judge_race NOT IN ('White', 'Hispanic');

CREATE TABLE Players (PlayerID INT, PlayerName VARCHAR(50), Age INT, Country VARCHAR(50)); INSERT INTO Players (PlayerID, PlayerName, Age, Country) VALUES (1, 'John Doe', 25, 'USA'); INSERT INTO Players (PlayerID, PlayerName, Age, Country) VALUES (2, 'Jane Smith', 30, 'Canada'); INSERT INTO Players (PlayerID, PlayerName, Age, Country) VALUES (3, 'Hans Schmidt', 35, 'Germany');
Q: Delete all players from Germany who are older than 30.
A: DELETE FROM Players WHERE Country = 'Germany' AND Age > 30;

CREATE TABLE agricultural_innovation_projects_region (id INT, project_name VARCHAR(50), budget FLOAT, region VARCHAR(50)); INSERT INTO agricultural_innovation_projects_region (id, project_name, budget, region) VALUES (1, 'Drip Irrigation', 250000.00, 'African'), (2, 'Livestock Genetics', 320000.00, 'Asian'), (3, 'Crop Sensors', 400000.00, 'North American');
Q: What is the average budget for agricultural innovation projects in the 'African' region in the 'agricultural_innovation_projects_region' table?
A: SELECT AVG(budget) FROM agricultural_innovation_projects_region WHERE region = 'African';

CREATE TABLE clients (id INT, age INT, financial_wellbeing_score INT); CREATE TABLE loans (id INT, client_id INT, is_socially_responsible BOOLEAN); INSERT INTO clients (id, age, financial_wellbeing_score) VALUES (1, 27, 7), (2, 35, 8), (3, 23, 6), (4, 31, 9), (5, 45, 10); INSERT INTO loans (id, client_id, is_socially_responsible) VALUES (1, 1, true), (2, 1, false), (3, 2, true), (4, 3, false), (5, 4, true), (6, 5, true);
Q: What is the average financial wellbeing score of clients in the age group 25-34 who have taken socially responsible loans?
A: SELECT AVG(c.financial_wellbeing_score) as avg_score FROM clients c JOIN loans l ON c.id = l.client_id WHERE c.age BETWEEN 25 AND 34 AND l.is_socially_responsible = true;

CREATE TABLE experiments (id INT, name VARCHAR(50), technology VARCHAR(50), description TEXT, target VARCHAR(50)); INSERT INTO experiments (id, name, technology, description, target) VALUES (2, 'Experiment2', 'CRISPR', 'Gene editing using CRISPR...', 'Plants');
