CREATE TABLE cities (city_id INT, city_name TEXT, state_id INT, population INT);CREATE TABLE states (state_id INT, state_name TEXT);
Q: Find the average population of cities in each state, grouped by state
A: SELECT s.state_name, AVG(c.population)  FROM cities c INNER JOIN states s ON c.state_id = s.state_id GROUP BY s.state_name;

CREATE TABLE company (id INT, name VARCHAR(255), country VARCHAR(255));CREATE TABLE extraction (company_id INT, mineral VARCHAR(255), amount INT);
Q: Which minerals were extracted in quantities greater than 1000 tons by companies that have mining operations in South America?
A: SELECT DISTINCT e.mineral FROM extraction e JOIN company c ON e.company_id = c.id WHERE c.country LIKE '%South America%' AND e.amount > 1000;

CREATE TABLE SalesData (SaleID INT, VehicleID INT, Country TEXT, SaleDate DATE);
Q: How many electric vehicles have been sold in the United States in Q1 and Q2 of 2023?
A: SELECT COUNT(*) FROM SalesData WHERE Country = 'United States' AND SaleDate >= '2023-01-01' AND SaleDate < '2023-07-01';

CREATE TABLE hydroelectric_projects (id INT, name TEXT, year INT, investment FLOAT); CREATE VIEW southeast_asia AS SELECT * FROM regions WHERE name = 'Southeast Asia';
Q: What was the total investment in hydroelectric projects in Southeast Asia in 2019?
A: SELECT SUM(investment) FROM hydroelectric_projects JOIN southeast_asia ON hydroelectric_projects.location = southeast_asia.id WHERE year = 2019;

CREATE TABLE boroughs (borough_id INT, borough_name VARCHAR(255)); CREATE TABLE charging_stations (station_id INT, station_name VARCHAR(255), borough_id INT, station_type VARCHAR(255));
Q: How many electric vehicle charging stations are there in each borough of New York City?
A: SELECT b.borough_name, COUNT(c.station_id) FROM boroughs b INNER JOIN charging_stations c ON b.borough_id = c.borough_id WHERE c.station_type = 'Electric' GROUP BY b.borough_name;

