A: SELECT SUM(daily_production_rate) FROM production_figure WHERE well_name = 'B-2';

CREATE TABLE equipment_maintenance (equipment_type TEXT, cost FLOAT); INSERT INTO equipment_maintenance (equipment_type, cost) VALUES ('Tank', 12000), ('Fighter Jet', 35000), ('Helicopter', 18000), ('Drone', 9000);
Q: Which military equipment type has the lowest maintenance cost?
A: SELECT equipment_type, cost FROM equipment_maintenance ORDER BY cost ASC LIMIT 1;

CREATE TABLE products (id INT, name VARCHAR(255)); INSERT INTO products (id, name) VALUES (1, 'Product K'); INSERT INTO products (id, name) VALUES (2, 'Product L'); CREATE TABLE food_safety_inspections (id INT, product_id INT, inspection_date DATE); INSERT INTO food_safety_inspections (id, product_id, inspection_date) VALUES (1, 1, '2022-01-01'); INSERT INTO food_safety_inspections (id, product_id, inspection_date) VALUES (2, 1, '2022-02-01'); INSERT INTO food_safety_inspections (id, product_id, inspection_date) VALUES (3, 2, '2022-03-01');
Q: What is the earliest food safety inspection date for each product?
A: SELECT p.name AS product_name, MIN(f.inspection_date) AS earliest_inspection_date FROM products p JOIN food_safety_inspections f ON p.id = f.product_id GROUP BY p.name;

CREATE TABLE hotel_bookings(booking_id INT, hotel_id INT, bookings INT); CREATE TABLE hotels(hotel_id INT, hotel_name VARCHAR(50), country VARCHAR(50), is_eco_friendly BOOLEAN);
Q: Which eco-friendly hotels in Canada have the most bookings?
A: SELECT h.hotel_name, SUM(hb.bookings) as total_bookings FROM hotels h JOIN hotel_bookings hb ON h.hotel_id = hb.hotel_id WHERE h.is_eco_friendly = TRUE AND h.country = 'Canada' GROUP BY h.hotel_id ORDER BY total_bookings DESC;

